print("X_train_scaled std (should be ~1):", X_train_scaled.std())

"""Step 14: Define the sigmoid function and cost function

This sets up the two core building blocks of logistic regression, since we're writing it manually (sklearn's LogisticRegression doesn't let us track cost per iteration, which is what you want):

sigmoid(z) — converts any number into a value between 0 and 1 (a probability). Logistic regression predicts z = w·X + b, then squashes it through this function to get a probability of Outcome = 1.
compute_cost(X, y, w, b) — calculates the log loss (also called binary cross-entropy), which measures how wrong the model's predictions are compared to actual labels. Lower cost = better fit.

eps and np.clip are there to avoid a math error (log(0) is undefined) in edge cases.
"""

def sigmoid(z):
    return 1 / (1 + np.exp(-z))

def compute_cost(X, y, w, b):
    m = X.shape[0]
    z = np.dot(X, w) + b
    y_hat = sigmoid(z)

    eps = 1e-15
    y_hat = np.clip(y_hat, eps, 1 - eps)

    cost = -(1/m) * np.sum(y * np.log(y_hat) + (1 - y) * np.log(1 - y_hat))
    return cost

"""Step 15: Define the gradient descent training function

What this does, step by step:

w = np.zeros(n) and b = 0.0 — starts with all weights and bias at 0 (no knowledge yet)
Loops n_iters times. In each iteration:

Computes predictions (y_hat) using current w, b
Computes the gradient (dw, db) — the direction that reduces cost the fastest
Updates w and b by stepping a little bit (controlled by lr, the learning rate) in that direction
Records the cost on both training data and test data — this is exactly what you wanted: cost tracked per iteration, for train and test separately


Every 100 iterations, prints the current cost so you can watch it improve as it runs

This cell just defines the function — it doesn't run anything yet

"""

def gradient_descent(X_train, y_train, X_test, y_test, lr=0.1, n_iters=2000):
    m, n = X_train.shape
    w = np.zeros(n)
    b = 0.0

    J_train_history = []
    J_test_history = []

    for i in range(n_iters):
        z = np.dot(X_train, w) + b
        y_hat = sigmoid(z)

        dw = (1/m) * np.dot(X_train.T, (y_hat - y_train))
        db = (1/m) * np.sum(y_hat - y_train)

        w = w - lr * dw
        b = b - lr * db

        J_train_history.append(compute_cost(X_train, y_train, w, b))
        J_test_history.append(compute_cost(X_test, y_test, w, b))

        if i % 100 == 0:
            print(f"Iter {i:4d} | Train Cost: {J_train_history[-1]:.4f} | Test Cost: {J_test_history[-1]:.4f}")

    return w, b, J_train_history, J_test_history

"""Step 16: Run the training (gradient descent)

What this does:

learning_rate = 0.1 — controls how big a step we take each iteration. Too high → cost can bounce around or diverge. Too low → training is very slow.
n_iterations = 3000 — how many times we update w and b. We're deliberately setting this high for now — in a later step you'll look at the cost plot and pick the iteration count that generalizes best, then we can re-run with that exact number.
y_train_arr, y_test_arr — converts y_train/y_test (which are pandas Series) into plain numpy arrays, since our gradient_descent function does numpy math operations (np.dot, etc.) which work more reliably with arrays than pandas Series.
The function will print cost every 100 iterations while it trains, so you can watch it live.
At the end, w (8 weight values, one per feature) and b (a single bias number) are your trained logistic regression parameters.
"""

learning_rate = 0.1
n_iterations = 3000

y_train_arr = np.array(y_train).flatten()
y_test_arr = np.array(y_test).flatten()

w, b, J_train_history, J_test_history = gradient_descent(
    X_train_scaled, y_train_arr,
    X_test_scaled, y_test_arr,
    lr=learning_rate,
    n_iters=n_iterations
)

print("\nFinal weights (w):", w)
print("Final bias (b):", b)

"""Step 17: Plot Cost (J) vs Iterations — Training vs Testing

What to look for in this plot:

Both lines dropping together and flattening out → good, model is learning and generalizing well

Training cost keeps dropping but testing cost starts going back up → that's the point where the model starts overfitting (memorizing training data instead of learning general patterns). The iteration number where testing cost is at its lowest point (just before it starts rising) is usually the best choice.

Both lines flatten out early and don't move much after → you might not need all 3000 iterations; fewer would work just as well and train faster.

This is the plot you'll use to pick your final n_iterations value — look at where the orange (test) line is lowest, note that iteration number, and tell me what you'd like to use. We'll then re-run training with that exact number in the next step.
"""

plt.figure(figsize=(10,6))
plt.plot(range(n_iterations), J_train_history, label='Training Cost', color='blue')
plt.plot(range(n_iterations), J_test_history, label='Testing Cost', color='orange')
plt.xlabel('Iterations')
plt.ylabel('Cost (J)')
plt.title('Cost Function vs Iterations')
plt.legend()
plt.grid(True)
plt.show()

"""This is a great looking plot. Here's how to read it:

Both curves drop sharply in the first ~100–200 iterations, then flatten out by around iteration 500
After that, both lines stay essentially flat all the way to 3000 — no improvement happening
No overfitting — the testing cost (orange) stays below the training cost (blue) throughout, and never starts rising. So your model isn't memorizing the training data; it's generalizing fine.


Since nothing changes after ~500 iterations, you're just wasting compute running 3000. A good choice here would be:
n_iterations = 500 (or even 300 — it's already basically flat by then)
This gives you the same model quality as 3000 iterations, just faster.
"""

n_iterations_final = 500   # change this if you'd like a different number

w, b, J_train_history, J_test_history = gradient_descent(
    X_train_scaled, y_train_arr,
    X_test_scaled, y_test_arr,
    lr=learning_rate,
    n_iters=n_iterations_final
)

print("\nFinal weights (w):", w)
print("Final bias (b):", b)
print("Final training cost:", J_train_history[-1])
print("Final testing cost:", J_test_history[-1])

"""Step 19: Make predictions (train and test)

What this does:

predict() — takes your features and trained w, b, computes the probability (y_hat) using the sigmoid function, then converts that probability into a 0 or 1 prediction. If probability ≥ 0.5, predict 1 (diabetic); otherwise predict 0 (not diabetic).

y_pred_train — predictions on the training set (using X_train_scaled, the correctly scaled data — this fixes the bug from your original notebook where it accidentally used unscaled X_train)

y_pred_test — predictions on the test set (using X_test_scaled)
"""

def predict(X, w, b, threshold=0.5):
    z = np.dot(X, w) + b
    y_hat = sigmoid(z)
    return (y_hat >= threshold).astype(int)

y_pred_train = predict(X_train_scaled, w, b)
y_pred_test = predict(X_test_scaled, w, b)

print("First 20 train predictions:", y_pred_train[:20])
print("First 20 test predictions:", y_pred_test[:20])

