prec_train_final = precision_score(y_train_arr, y_pred_train_final)
rec_train_final = recall_score(y_train_arr, y_pred_train_final)
f1_train_final = f1_score(y_train_arr, y_pred_train_final)

prec_test_final = precision_score(y_test_arr, y_pred_test_final)
rec_test_final = recall_score(y_test_arr, y_pred_test_final)
