fig, axes = plt.subplots(1, 2, figsize=(12, 5))

sns.heatmap(cm_train_final, annot=True, fmt='d', cmap='Blues', ax=axes[0])
axes[0].set_title(f'Training (Threshold={final_threshold})\nAcc: {acc_train_final:.3f}, Recall: {rec_train_final:.3f}')
