X_new

"""Step E: Run predictions on the new form responses"""

X_new_scaled = sc.transform(X_new)

z_new = np.dot(X_new_scaled, w) + b
y_prob_new = sigmoid(z_new)
y_pred_new = (y_prob_new >= final_threshold).astype(int)

results_df = X_new.copy()
results_df['Predicted_Probability'] = y_prob_new
results_df['Predicted_Outcome'] = y_pred_new

results_df

if 'Outcome' in responses_df.columns:
    results_df['Actual_Outcome'] = responses_df['Outcome']
    results_df['Correct'] = results_df['Predicted_Outcome'] == results_df['Actual_Outcome']

results_df